parameters.query:
=UPDATE reddit_posts 
SET processed = 1 
WHERE id IN ({{ $('Format Posts for LLM').first().json.post_ids.length > 0 ? $('Format Posts for LLM').first().json.post_ids.map(id => "'" + id + "'").join(',') : "''" }});
